#!/usr/bin/env node
import { program } from "commander";
import path from "path";
import fs from "fs/promises";
import { transpile, ModuleKind, JsxEmit } from "typescript";
/**
 * Dynamically imports a module, bypassing the cache.
 * @param modulePath The path to the module to import.
 * @returns The module's default export.
 */
async function importFresh(modulePath) {
    const cacheBuster = `?update=${new Date().getTime()}`;
    // Correctly format the path for dynamic import, especially on Windows.
    const fileUrl = "file:///" + path.resolve(modulePath).replace(/\\/g, "/");
    return await import(fileUrl + cacheBuster);
}
/**
 * Finds, transpiles, and loads the graph configuration file.
 * @param configPath The path to the user's graph config file.
 * @returns The configuration object.
 */
async function findAndLoadConfig(configPath) {
    const absoluteConfigPath = path.resolve(process.cwd(), configPath);
    try {
        await fs.access(absoluteConfigPath);
    }
    catch (error) {
        console.error(`Error: Could not find config file at: ${absoluteConfigPath}`);
        process.exit(1);
    }
    const fileContent = await fs.readFile(absoluteConfigPath, "utf8");
    // Transpile the user's TypeScript config into an ES Module string.
    const transpiledCode = transpile(fileContent, {
        module: ModuleKind.ESNext,
        jsx: JsxEmit.React,
    });
    // Write the transpiled code to a temporary .mjs file to ensure it's treated as an ES Module.
    const tempDir = path.dirname(absoluteConfigPath);
    const tempFileName = `zg.config.temp.${Date.now()}.mjs`;
    const tempPath = path.join(tempDir, tempFileName);
    await fs.writeFile(tempPath, transpiledCode);
    try {
        // Dynamically import the transpiled ES Module.
        const configModule = await importFresh(tempPath);
        return configModule.default;
    }
    catch (error) {
        console.error(`Error loading or parsing config file ${configPath}:`, error);
        process.exit(1);
    }
    finally {
        // Always clean up the temporary file.
        if (tempPath) {
            try {
                await fs.unlink(tempPath);
            }
            catch (unlinkError) {
                // It's not critical if this fails, but good to know.
                console.error(`Failed to clean up temporary config file: ${unlinkError}`);
            }
        }
    }
}
/**
 * Generates the main ZgClient class and type definitions.
 * @param config The validated graph configuration.
 * @returns A string containing the generated TypeScript code for `index.ts`.
 */
function generateClientCode(config) {
    const { nodes, edges } = config.schema;
    const nodeNames = Object.keys(nodes);
    const typeExports = nodeNames.map((name) => capitalize(name)).join(", ");
    // Generate a TypeScript interface for each node type.
    const nodeInterfaces = nodeNames
        .map((nodeName) => {
        const shape = nodes[nodeName].shape;
        const properties = Object.keys(shape)
            .filter((k) => k !== "id")
            .map((key) => `  ${key}: ${zodTypeToTsType(shape[key])};`)
            .join("\n");
        const edgeProperties = generateEdgeProperties(nodeName, edges);
        return `export interface ${capitalize(nodeName)} {\n  id: string;\n${properties}\n${edgeProperties}\n}`;
    })
        .join("\n\n");
    const clientProperties = nodeNames
        .map((name) => `  public readonly ${name}: Collection<${capitalize(name)}>;`)
        .join("\n");
    const clientConstructor = nodeNames
        .map((name) => `    this.${name} = new Collection<${capitalize(name)}>();`)
        .join("\n");
    return `// Generated by @zgdb/cli. Do not edit.\n
import { Collection } from './collection';

// --- Node Interfaces ---
${nodeInterfaces}

// --- Type Exports ---
export type { ${typeExports} };

// --- Zg Client ---
export class ZgClient {
${clientProperties}

  constructor() {
${clientConstructor}
  }
}

/**
 * Creates a new synchronous, in-memory graph client.
 */
export function createClient(): ZgClient {
  return new ZgClient();
}
`;
}
/**
 * Generates the edge properties (relationships) for a given node interface.
 * @param nodeName The name of the current node.
 * @param edges The array of edge definitions from the config.
 * @returns A string of property definitions for the interface.
 */
function generateEdgeProperties(nodeName, edges) {
    return edges
        .filter((edge) => edge.source === nodeName || edge.target === nodeName)
        .map((edge) => {
        if (edge.source === nodeName) {
            // This node is the source of the edge
            const targetType = capitalize(edge.target);
            const propName = edge.name.forward;
            const type = edge.cardinality === "one-to-many"
                ? `${targetType}[]`
                : `${targetType} | undefined`;
            return `  ${propName}: ${type};`;
        }
        else {
            // This node is the target of the edge
            const sourceType = capitalize(edge.source);
            const propName = edge.name.backward;
            // Based on standard relationship modeling, the "many" side of a one-to-many
            // holds a single reference to the "one" side.
            const type = edge.cardinality === "one-to-many"
                ? `${sourceType}`
                : `${sourceType}[]`;
            return `  ${propName}: ${type};`;
        }
    })
        .join("\n");
}
/**
 * A basic mapping from Zod types to TypeScript types for code generation.
 * @param type The Zod type object.
 * @returns A TypeScript type as a string.
 */
function zodTypeToTsType(type) {
    const typeName = type.constructor.name;
    if (typeName.startsWith("Zod")) {
        return type._def.typeName.replace("Zod", "").toLowerCase();
    }
    return "any";
}
/**
 * Generates the Collection class used for managing nodes.
 * @returns A string containing the TypeScript code for `collection.ts`.
 */
function generateCollectionCode() {
    return `// Generated by @zgdb/cli. Do not edit.

/**
 * A simple in-memory collection for managing nodes of a specific type.
 */
export class Collection<T extends { id: string }> {
    private items = new Map<string, T>();

    /**
     * Adds or updates an item in the collection.
     * @param itemData The full item object, including its ID.
     * @returns The added or updated item.
     */
    add(itemData: T): T {
        // Using an explicit 'add' method clarifies intent over a generic 'set'.
        // This could be extended with validation or hooks in the future.
        this.items.set(itemData.id, itemData);
        return itemData;
    }

    /**
     * Retrieves an item by its ID.
     * @param id The ID of the item to retrieve.
     * @returns The item, or undefined if not found.
     */
    get(id: string): T | undefined {
        return this.items.get(id);
    }

    /**
     * Allows the collection to be used in 'for...of' loops.
     */
    *[Symbol.iterator]() {
        for (const item of this.items.values()) {
            yield item;
        }
    }
}
`;
}
function capitalize(s) {
    return s.charAt(0).toUpperCase() + s.slice(1);
}
// --- Program Definition ---
program
    .command("build")
    .description("Build the graph client from your schema file.")
    .option("-c, --config <path>", "Path to the graph config file", "graph.config.ts")
    .option("-o, --output <path>", "Path to the output directory for the generated client", "./src/generated/graph")
    .action(async (options) => {
    console.log(`Building graph client from ${options.config}...`);
    const config = await findAndLoadConfig(options.config);
    if (!config || !config.schema) {
        console.error("Invalid configuration: 'schema' property is missing or the config file is invalid.");
        return;
    }
    const outputDir = path.resolve(process.cwd(), options.output);
    await fs.mkdir(outputDir, { recursive: true });
    // Generate and write the client code
    const clientCode = generateClientCode(config);
    await fs.writeFile(path.join(outputDir, "index.ts"), clientCode, "utf8");
    // Generate and write the helper collection class
    const collectionCode = generateCollectionCode();
    await fs.writeFile(path.join(outputDir, "collection.ts"), collectionCode, "utf8");
    console.log(`✅ Graph client generated successfully at ${outputDir}`);
});
program.parse(process.argv);
